import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { ShoppingCart, LogOut, User, Store } from 'lucide-react';
import { useCart } from '../context/CartContext';

const Header = () => {
  const { user, logout, isAuthenticated } = useAuth();
  const { count } = useCart();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  return (
    <header style={headerStyle}>
      <div style={container}>
        {/* Logo / Nombre */}
        <Link to="/" style={logoStyle}>
          <Store size={28} color="#e67e22" />
          <span style={logoText}>Ofertas<span style={{ color: '#e67e22' }}>App</span></span>
        </Link>

        {/* Navegación */}
        <nav style={navStyle}>
          {isAuthenticated ? (
            <div style={userActions}>
              {user?.rol === 'cliente' && (
                <Link to="/carrito" style={cartBadge}>
                  <ShoppingCart size={20} />
                  {count > 0 && <span style={badgeCount}>{count}</span>}
                </Link>
              )}
              
              <div style={userInfo}>
                <User size={18} color="#64748b" />
                <span style={userName}>{user?.nombre || 'Usuario'}</span>
              </div>

              <button onClick={handleLogout} style={btnLogout}>
                <LogOut size={18} />
                <span className="hide-mobile">Salir</span>
              </button>
            </div>
          ) : (
            <div style={authButtons}>
              <Link to="/login" style={btnLogin}>
                Ingresar
              </Link>
              <Link to="/registro" style={btnRegister}>
                Crear cuenta
              </Link>
            </div>
          )}
        </nav>
      </div>
    </header>
  );
};

// --- ESTILOS CORREGIDOS ---
const headerStyle = {
  height: '75px',
  background: 'white',
  borderBottom: '1px solid #e2e8f0',
  display: 'flex',
  alignItems: 'center',
  position: 'sticky',
  top: 0,
  zIndex: 1000,
  boxShadow: '0 2px 4px rgba(0,0,0,0.02)'
};

const container = {
  width: '100%',
  maxWidth: '1200px',
  margin: '0 auto',
  padding: '0 25px',
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center'
};

const logoStyle = {
  display: 'flex',
  alignItems: 'center',
  gap: '10px',
  textDecoration: 'none'
};

const logoText = {
  fontSize: '1.5rem',
  fontWeight: '900',
  color: '#1e293b',
  letterSpacing: '-0.5px'
};

const navStyle = {
  display: 'flex',
  alignItems: 'center'
};

// CONTENEDOR DE BOTONES (Aquí corregimos la superposición)
const authButtons = {
  display: 'flex',
  alignItems: 'center',
  gap: '15px' // Espacio suficiente entre Ingresar y Crear Cuenta
};

const btnLogin = {
  textDecoration: 'none',
  color: '#64748b',
  fontWeight: '600',
  fontSize: '0.95rem',
  padding: '10px 20px',
  borderRadius: '12px',
  transition: '0.2s'
};

const btnRegister = {
  textDecoration: 'none',
  background: '#1e293b',
  color: 'white',
  fontWeight: 'bold',
  fontSize: '0.95rem',
  padding: '10px 22px',
  borderRadius: '12px',
  boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)',
  transition: '0.2s'
};

// Estilos de usuario logueado
const userActions = {
  display: 'flex',
  alignItems: 'center',
  gap: '20px'
};

const userInfo = {
  display: 'flex',
  alignItems: 'center',
  gap: '8px',
  background: '#f8fafc',
  padding: '8px 15px',
  borderRadius: '10px',
  border: '1px solid #f1f5f9'
};

const userName = {
  color: '#1e293b',
  fontWeight: '600',
  fontSize: '0.9rem'
};

const btnLogout = {
  background: 'none',
  border: 'none',
  color: '#ef4444',
  cursor: 'pointer',
  display: 'flex',
  alignItems: 'center',
  gap: '8px',
  fontWeight: 'bold',
  fontSize: '0.9rem'
};

const cartBadge = {
  position: 'relative',
  color: '#1e293b',
  padding: '8px'
};

const badgeCount = {
  position: 'absolute',
  top: '-2px',
  right: '-2px',
  background: '#e67e22',
  color: 'white',
  fontSize: '0.7rem',
  fontWeight: 'bold',
  width: '18px',
  height: '18px',
  borderRadius: '50%',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  border: '2px solid white'
};

export default Header;
